import{_ as i,o as a,c as t,ae as l}from"./chunks/framework.DeBUZsJm.js";const g=JSON.parse('{"title":"Setup","description":"","frontmatter":{},"headers":[],"relativePath":"setup.md","filePath":"setup.md","lastUpdated":1775513914000}'),o={name:"setup.md"};function n(r,e,s,d,u,p){return a(),t("div",null,[...e[0]||(e[0]=[l('<h1 id="setup" tabindex="-1">Setup <a class="header-anchor" href="#setup" aria-label="Permalink to &quot;Setup&quot;">​</a></h1><h2 id="requirements" tabindex="-1">Requirements <a class="header-anchor" href="#requirements" aria-label="Permalink to &quot;Requirements&quot;">​</a></h2><p>Astrogram plugins must be compiled against the same native environment as the client build:</p><ul><li>same platform</li><li>same pointer size</li><li>same compiler ABI</li><li>same Qt major/minor version</li><li>same Astrogram plugin API version</li></ul><p>If any of these differ, the plugin manager will reject the binary as an ABI mismatch.</p><h2 id="important-paths" tabindex="-1">Important paths <a class="header-anchor" href="#important-paths" aria-label="Permalink to &quot;Important paths&quot;">​</a></h2><ul><li>Plugins folder: <code>&lt;working dir&gt;/tdata/plugins</code></li><li>Manual enable/disable state: <code>&lt;working dir&gt;/tdata/plugins.json</code></li><li>Safe mode flag: <code>&lt;working dir&gt;/tdata/plugins.safe-mode</code></li><li>Main plugin log: <code>&lt;working dir&gt;/tdata/plugins.log</code></li><li>Recovery state: <code>&lt;working dir&gt;/tdata/plugins.recovery.json</code></li><li>Trace log: <code>&lt;working dir&gt;/tdata/plugins.trace.jsonl</code></li></ul><h2 id="source-files-you-need" tabindex="-1">Source files you need <a class="header-anchor" href="#source-files-you-need" aria-label="Permalink to &quot;Source files you need&quot;">​</a></h2><ul><li>API header: <code>Telegram/SourceFiles/plugins/plugins_api.h</code></li><li>Example plugins: <code>Telegram/Plugins/Examples</code></li><li>Catalog versions: <code>PluginCatalog/&lt;plugin&gt;/&lt;version&gt;</code></li></ul><h2 id="build-expectations" tabindex="-1">Build expectations <a class="header-anchor" href="#build-expectations" aria-label="Permalink to &quot;Build expectations&quot;">​</a></h2><p>At minimum:</p><ul><li><code>QtCore</code></li><li>for UI plugins: <code>QtWidgets</code></li><li>for network plugins: <code>QtNetwork</code></li></ul><p>Astrogram ships selective GitHub Actions workflows for plugin builds, so small plugin edits do not need to rebuild the whole plugin catalog every time.</p><h2 id="installing-a-plugin" tabindex="-1">Installing a plugin <a class="header-anchor" href="#installing-a-plugin" aria-label="Permalink to &quot;Installing a plugin&quot;">​</a></h2><ol><li>Build a shared library.</li><li>Rename the output to <code>.tgd</code>.</li><li>Copy it into <code>&lt;working dir&gt;/tdata/plugins</code>.</li><li>Open <code>Settings &gt; Astrogram &gt; Plugins</code>.</li></ol><p>The client reloads plugins automatically after install or update.</p><h2 id="preview-metadata" tabindex="-1">Preview metadata <a class="header-anchor" href="#preview-metadata" aria-label="Permalink to &quot;Preview metadata&quot;">​</a></h2><p>Use <code>TGD_PLUGIN_PREVIEW(...)</code> so Astrogram can show install/update metadata before running any plugin code.</p><p>This is how in-chat plugin installation can show:</p><ul><li>plugin name</li><li>version</li><li>author</li><li>description</li><li>website</li><li>optional icon reference</li></ul><p>without loading the binary itself.</p>',21)])])}const m=i(o,[["render",n]]);export{g as __pageData,m as default};
